trait Strategy { fn execute(&self, x: i32) -> i32; }

struct Context {
    strategy: Box<dyn Strategy>,
}

impl Context {
    fn execute(&self, x: i32) -> i32 {
        self.strategy.execute(x)
    }
}

struct AddOne;
impl Strategy for AddOne { fn execute(&self, x: i32) -> i32 { x + 1 } }

fn main() {
    let context = Context { strategy: Box::new(AddOne) };
    println!("{}", context.execute(5));
}

